var e=[{id:`L2_1`,type:`dialog`,speaker:`LAIKA_CANARY_NULL_NULL`,text:{KOREA:`……커흑!?`,JPN:`……がはっ！？`,ENG:`...Kuh?!`,TWN:`……嚇呃？！`},stage:{bg:`GAUNTLET`,slots:{L:null,C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`라이카! 정신 좀 차려 봐요!`,JPN:`ライカ！　しっかりして！`,ENG:`Laika! Get up!`,TWN:`萊卡！振作一點！`},stage:{bg:`GAUNTLET`,slots:{L:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_SERIOUS`},C:{char_id:`LAIKA_CANARY_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`아, 안 돼! 바즈라가……!`,JPN:`そ、そんな！　ヴァジュラが……！`,ENG:`N-no! Vajra is...!`,TWN:`不，不可以！金剛杵……！`},stage:{bg:`GAUNTLET`,slots:{L:null,C:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`GOLD_CHARADE_NULL_NULL`,text:{KOREA:`어딜 도망가시나!`,JPN:`どこに逃げるつもり？`,ENG:`Where do you think you're going?!`,TWN:`想逃！`},stage:{bg:`GAUNTLET`,slots:{L:null,C:{char_id:`GOLD_CHARADE_NULL_NULL`,face:`UNIT_PRIDE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`하윽……!`,JPN:`はうっ……！`,ENG:`Hagh...!`,TWN:`唔呃……！`},stage:{bg:`GAUNTLET`,slots:{L:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_DESPAIR`},C:null,R:{char_id:`GOLD_CHARADE_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L17_1`,type:`dialog`,speaker:`GOLD_CHARADE_NULL_NULL`,text:{KOREA:`그러게 처음부터 얌전히 잡혔으면 얼마나 좋아, 꼬마야.`,JPN:`だから最初から大人しく捕まっていればよかったのよ、ちびちゃん。`,ENG:`See how easy things would've been if you didn't run away from me from the start, little girl?`,TWN:`所以說，一開始就乖乖束手就擒不是很好嗎，小鬼？`},stage:{bg:`GAUNTLET`,slots:{L:{char_id:`INTERN_FENRIR_NULL_NULL`,face:`UNIT_DESPAIR`},C:null,R:{char_id:`GOLD_CHARADE_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L20_1`,type:`dialog`,speaker:`GOLD_CHARADE_NULL_NULL`,text:{KOREA:`자, 이걸로 화력 담당인 스나이퍼부터 리타이어려나?`,JPN:`さあ、これで火力担当のスナイパーからリタイアかしらね？`,ENG:`Now, does this mean that your damage-dealing Sniper is out first?`,TWN:`這樣應該算淘汰掉負責火力的狙擊手了吧？`},stage:{bg:`GAUNTLET`,slots:{L:null,C:null,R:{char_id:`GOLD_CHARADE_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L22_1`,type:`dialog`,speaker:`FELICETTE_CANARY_NULL_NULL`,text:{KOREA:`노엘!!`,JPN:`ノエル！！`,ENG:`Noelle!!`,TWN:`洛艾兒！！`},stage:{bg:`GAUNTLET`,slots:{L:null,C:{char_id:`FELICETTE_CANARY_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L30_1`,type:`dialog`,speaker:`GOLD_CHARADE_NULL_NULL`,text:{KOREA:`얌전히 있어, 루이즈.`,JPN:`大人しくしていなさい、ルイーズ。`,ENG:`You stay right there, Louisé.`,TWN:`不要亂動，露易絲。`},stage:{bg:`GAUNTLET`,slots:{L:null,C:{char_id:`GOLD_CHARADE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L31_1`,type:`dialog`,speaker:`GOLD_CHARADE_NULL_NULL`,text:{KOREA:`나는 가장 맛있는 건 나중에 먹는 타입이거든.`,JPN:`私はメインディッシュは一番最後まで取っておくタイプなの。`,ENG:`I'm the type to save the best for last.`,TWN:`我這個人一向喜歡把好吃的留到最後。`},stage:{bg:`GAUNTLET`,slots:{L:null,C:{char_id:`GOLD_CHARADE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L32_1`,type:`dialog`,speaker:`GOLD_CHARADE_NULL_NULL`,text:{KOREA:`네 차례는 저기 한방에 나가떨어진 네 동료를 끝장낸 다음이니까 조금만 기다려.`,JPN:`あそこに倒れているあなたの仲間を終わらせてからがあなたの番だから、少し待っていなさい。`,ENG:`Be patient. Your turn will come after I end your little friends first.`,TWN:`你再等一等，等我解決掉你那些不堪一擊的同伴後就換你囉。`},stage:{bg:`GAUNTLET`,slots:{L:null,C:{char_id:`GOLD_CHARADE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L34_1`,type:`dialog`,speaker:`INTERN_FENRIR_NULL_NULL`,text:{KOREA:`아, 아직……!!`,JPN:`ま、まだ……！！`,ENG:`I-I won't...!!`,TWN:`我，我還……！！`},stage:{bg:`GAUNTLET`,slots:{L:null,C:{char_id:`GOLD_CHARADE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L35_1`,type:`dialog`,speaker:`GOLD_CHARADE_NULL_NULL`,text:{KOREA:`으응? 아직 의식이 있네?`,JPN:`あら？　まだ動けるの？`,ENG:`Hmm? Still have some fight in you?`,TWN:`嗯？還有意識？`},stage:{bg:`GAUNTLET`,slots:{L:null,C:{char_id:`GOLD_CHARADE_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L36_1`,type:`dialog`,speaker:`GOLD_CHARADE_NULL_NULL`,text:{KOREA:`노엘이라고 했지? 꼴에 카운터라고 이 중에서는 네가 가장 튼튼하구나?`,JPN:`ノエルだっけ？　一応カウンターだけあって、この中じゃ一番頑丈みたいね。`,ENG:`Noelle, was it? Guess you're the strongest out of the bunch being a Counter and all.`,TWN:`你叫洛艾兒是吧？不愧是制裁者，這幾個人中就屬你最耐打？`},stage:{bg:`GAUNTLET`,slots:{L:null,C:{char_id:`GOLD_CHARADE_NULL_NULL`,face:`UNIT_LAUGH`},R:null}}}];export{e as default};